mapper.select:
SELECT * FROM faqs
category LIKE CONCAT('%', #{search}, '%') OR question LIKE CONCAT('%', #{search}, '%') OR answer LIKE CONCAT('%', #{search}, '%')
ORDER BY display_order ASC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE faqs
SET question = #{question},
    answer = #{answer},
    category = #{category},
    display_order = #{displayOrder}
WHERE id = #{id}
